CREATE OR REPLACE FUNCTION sync_module_subject_to_subject()
RETURNS TRIGGER AS $$
BEGIN
    IF (TG_OP = 'INSERT') THEN
        INSERT INTO subject (
            subject_id, unique_identifier, date_of_birth, gender,
            dob_collected, date_created, date_updated,
            owner_id, update_id, status_id
        )
        VALUES (
            NEW.subject_id, NEW.unique_identifier, NEW.date_of_birth, NEW.gender,
            NEW.dob_collected, NEW.date_created, NEW.date_updated,
            NEW.owner_id, NEW.update_id, NEW.status_id
        );
        RETURN NEW;
    ELSIF (TG_OP = 'UPDATE') THEN
        UPDATE subject SET
            unique_identifier = NEW.unique_identifier,
            date_of_birth = NEW.date_of_birth,
            gender = NEW.gender,
            dob_collected = NEW.dob_collected,
            date_created = NEW.date_created,
            date_updated = NEW.date_updated,
            owner_id = NEW.owner_id,
            update_id = NEW.update_id,
            status_id = NEW.status_id
        WHERE subject_id = OLD.subject_id;
        RETURN NEW;
    ELSIF (TG_OP = 'DELETE') THEN
        DELETE FROM subject WHERE subject_id = OLD.subject_id;
        RETURN OLD;
    END IF;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_sync_module_subject
AFTER INSERT OR UPDATE OR DELETE ON module_subject
FOR EACH ROW EXECUTE FUNCTION sync_module_subject_to_subject();
